from typing import List

def solve(nums: List[int]) -> int:
    n = len(nums)
    max_sum = 0

    # Iterate all possible ways to split into A, B, C
    # A is nums[0..i-1], B is nums[i..j-1], C is nums[j..n-1]
    for i in range(n + 1):
        for j in range(i, n + 1):
            # Compute XOR(A)
            xor_a = 0
            for num in nums[:i]:
                xor_a ^= num

            # Compute AND(B)
            and_b = (1 << 30) - 1  # Initialize with all bits set (for AND)
            if i == j:
                and_b = 0
            else:
                for num in nums[i:j]:
                    and_b &= num

            # Compute XOR(C)
            xor_c = 0
            for num in nums[j:]:
                xor_c ^= num

            current_sum = xor_a + and_b + xor_c
            if current_sum > max_sum:
                max_sum = current_sum

    return max_sum
